-- AL Governador: JHC legislacao executiva municipal parcial via Diario Municipal
-- Fonte: fonte interna de curadoria
-- Descoberta parcial: nao declarar inventario completo.

DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM candidatos WHERE slug = 'jhc' AND publicavel = true) THEN
    RAISE EXCEPTION 'jhc nao encontrado ou nao publicavel';
  END IF;
END $$;

